const STATUSES=[...new Set(Object.values(WORKFLOWS).flat())];
function workflowFor(jOrType){let t=typeof jOrType==='string'?jOrType:(jOrType?.type||'Service Call');return WORKFLOWS[t]||DEFAULT_WORKFLOW}
function nextStage(j){let wf=workflowFor(j);let i=wf.indexOf(j.status);return i>=0&&i<wf.length-1?wf[i+1]:null}
function firstMatchingStage(j,names){let wf=workflowFor(j);return names.find(x=>wf.includes(x))||null}
function setStage(j,stage,action){if(!stage)return; j.status=stage; j.updatedAt=now(); j.history=j.history||[]; j.history.unshift({at:now(),by:current?.name||'System',action:action||('Moved to '+stage)});}
function reportGeneratedStages(){return ['Report Generated','Customer Sign-off','Customer Signed','Report Shared','Coordinator Review','Closed']}
function signoffStageName(){return 'Customer Sign-off'}
