const $=id=>document.getElementById(id);
const now=()=>new Date().toISOString();
const esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const slug=s=>String(s||'').toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'').slice(0,70)||('id_'+Date.now());
const money=n=>Number(n||0).toLocaleString('en-IN',{maximumFractionDigits:2});
function toast(msg){let t=$('toast'); if(!t)return; t.textContent=msg;t.classList.remove('hidden');clearTimeout(t._x);t._x=setTimeout(()=>t.classList.add('hidden'),3000)}
