 if(!state.customers.length)state.customers=[{id:'cust_paypal',name:'PayPal India Pvt Ltd',contact:'',email:''},{id:'cust_swiggy',name:'Swiggy',contact:'',email:''},{id:'cust_tablespace',name:'Tablespace',contact:'',email:''},{id:'cust_clicktech',name:'Clicktech Retail Pvt Ltd',contact:'',email:''},{id:'cust_tekion',name:'Tekion',contact:'',email:''}];
